// Gera a lista de URLs para os últimos 30 dias
const dias = 30;
const hoje = new Date();
const items = [];

for (let i = dias; i >= 0; i--) {
  const d = new Date(hoje);
  d.setDate(d.getDate() - i);
  const ano = d.getFullYear();
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const dia = String(d.getDate()).padStart(2, '0');
  const dataStr = `${ano}${mes}${dia}`;
  const dataIso = `${ano}-${mes}-${dia}`;
  items.push({
    json: {
      url: `https://www.omie.es/en/file-download?parents=marginalpdbcpt&filename=marginalpdbcpt_${dataStr}.1`,
      data: dataIso
    }
  });
}

return items;

// ╔══════════════════════════════════════════════════════════════╗
// ║                    ⚙️  CONFIGURAÇÃO                          ║
// ║           Só precisas de editar esta secção                  ║
// ╚══════════════════════════════════════════════════════════════╝

const CONFIG = {

  consumo_kwh: 700,   // kWh/mês
  dias:         30,   // dias do período de faturação

  // ── Tarifas reguladas ERSE 2026 ────────────────────────────
  // Atualizar em janeiro de cada ano
  // Fonte: https://www.tiagofelicia.pt/tarifas-acesso-redes.html
  tar: {
    energia_kwh:  0.0607,   // €/kWh — tarifa simples BTN
    potencia_dia: 0.3436,   // €/dia — 6.9 kVA (alterar se mudares de potência)
  },

  // ── Tarifário FIXO ─────────────────────────────────────────
  // Preço por kWh e por dia contratados com o comercializador
  fixo: {
    nome:         "G9 Vantagem+",
    energia_kwh:  0.1348,   // €/kWh  — componente energia do contrato
    potencia_dia: 0.4498,   // €/dia  — componente potência do contrato
  },

  // ── Tarifário INDEXADO (OMIE) ───────────────────────────────
  // A TAR (tar.energia_kwh + tar.potencia_dia) é sempre somada por cima
  indexado: {
    nome:       "G9 Smart Index",
    margem_kwh: 0.0150,     // €/kWh  — margem do comercializador
    // Outros encargos fixos do comercializador (GGS, Fadeg, etc.) — €/kWh
    // Deixar a 0 se já estiverem incluídos na margem ou não se aplicarem
    outros_kwh: 0.0000,
  },

};

// ╔══════════════════════════════════════════════════════════════╗
// ║            NÃO É NECESSÁRIO EDITAR ABAIXO DAQUI             ║
// ╚══════════════════════════════════════════════════════════════╝

// ── Parse dos dados OMIE ──────────────────────────────────────
const todosPrecos = [];

for (const item of $input.all()) {
  const texto = item.json.data;
  if (!texto || typeof texto !== "string") continue;
  for (const linha of texto.split("\n")) {
    const partes = linha.trim().split(";");
    if (partes.length >= 5 && /^\d{4}$/.test(partes[0].trim())) {
      const preco = parseFloat(partes[4].replace(",", "."));
      if (!isNaN(preco)) todosPrecos.push(preco);
    }
  }
}

if (todosPrecos.length === 0) {
  return [{ json: { erro: "Sem dados OMIE disponíveis", media_omie: null } }];
}

// ── Cálculos ──────────────────────────────────────────────────
const { consumo_kwh, dias, tar, fixo, indexado } = CONFIG;

const mediaOmie = todosPrecos.reduce((a, b) => a + b, 0) / todosPrecos.length;

const custoFixo = (consumo_kwh * fixo.energia_kwh) + (dias * fixo.potencia_dia);

const precoKwhIndexado = (mediaOmie / 1000) + indexado.margem_kwh + indexado.outros_kwh + tar.energia_kwh;
const custoIndexado    = (consumo_kwh * precoKwhIndexado) + (dias * tar.potencia_dia);

const breakeven = (
  (custoFixo - dias * tar.potencia_dia) / consumo_kwh
  - indexado.margem_kwh
  - indexado.outros_kwh
  - tar.energia_kwh
) * 1000;

const poupanca     = Math.abs(custoFixo - custoIndexado);
const omieAlta     = mediaOmie > breakeven;
const recomendacao = omieAlta ? fixo.nome : indexado.nome;
const r            = (v) => Math.round(v * 100) / 100;

// ── Output ────────────────────────────────────────────────────
return [{
  json: {
    data_analise:           new Date().toISOString().split("T")[0],
    media_omie_eur_mwh:     r(mediaOmie),
    breakeven_eur_mwh:      r(breakeven),
    [`custo_${fixo.nome.toLowerCase().replace(/\W+/g,"_")}_eur`]:     r(custoFixo),
    [`custo_${indexado.nome.toLowerCase().replace(/\W+/g,"_")}_eur`]: r(custoIndexado),
    poupanca_eur:           r(poupanca),
    recomendacao,
    omie_alta:              omieAlta,
    num_precos_lidos:       todosPrecos.length,
    resumo: omieAlta
      ? `🚨 OMIE alta (${r(mediaOmie)} > ${r(breakeven)} €/MWh) — ${recomendacao} poupa ${r(poupanca)} €`
      : `✅ OMIE baixa (${r(mediaOmie)} < ${r(breakeven)} €/MWh) — ${recomendacao} poupa ${r(poupanca)} €`,
  }
}];
